module RefModule(
    input clk,
    input we,
    input [2:0] waddr,
    input [2:0] raddr1,
    input [2:0] raddr2,
    input [15:0] wdata,

    output [15:0] rdata1,
    output [15:0] rdata2
);

reg [15:0] obf_regs [7:0];

always @(posedge clk)
begin
    if (we)
        obf_regs[waddr] <= wdata;
end

assign rdata1 = obf_regs[raddr1];
assign rdata2 = obf_regs[raddr2];

endmodule
